import java.util.*;

public class Solution {
    public static long solve(long[][] points) {
        int n = points.length;
        if (n < 4) {
            return 0;
        }

        Map<String, Set<Long>> lines = new HashMap<>();

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long x1 = points[i][0], y1 = points[i][1];
                long x2 = points[j][0], y2 = points[j][1];
                String key;
                if (x1 == x2) {
                    key = "inf_" + x1;
                } else {
                    long dx = x2 - x1;
                    long dy = y2 - y1;
                    long gcd = gcd(dx, dy);
                    dx /= gcd;
                    dy /= gcd;
                    if (dx < 0) {
                        dx = -dx;
                        dy = -dy;
                    }
                    long interceptNum = y1 * dx - x1 * dy;
                    long interceptDen = dx;
                    gcd = gcd(interceptNum, interceptDen);
                    interceptNum /= gcd;
                    interceptDen /= gcd;
                    if (interceptDen < 0) {
                        interceptNum = -interceptNum;
                        interceptDen = -interceptDen;
                    }
                    key = dy + "_" + dx + "_" + interceptNum + "_" + interceptDen;
                }
                Set<Long> line = lines.getOrDefault(key, new HashSet<>());
                line.add((x1 << 32) | y1);
                line.add((x2 << 32) | y2);
                lines.put(key, line);
            }
        }

        Map<String, Integer> lineCounts = new HashMap<>();
        for (Map.Entry<String, Set<Long>> entry : lines.entrySet()) {
            if (entry.getValue().size() >= 2) {
                lineCounts.put(entry.getKey(), entry.getValue().size());
            }
        }

        long trapezoidCount = 0;
        List<String> keysList = new ArrayList<>(lineCounts.keySet());
        for (int i = 0; i < keysList.size(); i++) {
            for (int j = i + 1; j < keysList.size(); j++) {
                String key1 = keysList.get(i);
                String key2 = keysList.get(j);
                if (key1.startsWith("inf_") && key2.startsWith("inf_")) {
                    continue;
                }
                String[] parts1 = key1.split("_");
                String[] parts2 = key2.split("_");
                if (parts1[0].equals(parts2[0]) && parts1[1].equals(parts2[1])) {
                    int m = lineCounts.get(key1);
                    int k = lineCounts.get(key2);
                    trapezoidCount += (long) m * (m - 1) / 2 * k * (k - 1) / 2;
                }
            }
        }

        return trapezoidCount;
    }

    private static long gcd(long a, long b) {
        while (b != 0) {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}
