                    long dy = y2 - y1;
                    long g = gcd(dy, dx);
                    dy /= g;
                    dx /= g;
                    if (dx < 0) {
                        dy = -dy;
                        dx = -dx;
                    }
                    long interceptNum = y1 * dx - x1 * dy;
                    long interceptDen = dx;
                    g = gcd(interceptNum, interceptDen);
                    interceptNum /= g;
